glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec2 a_uv0;
in vec2 a_uv1;
in vec2 a_p;
in vec2 a_q;
out vec2 v_uv0;
out vec2 v_uv1;
out vec2 v_p;
out vec2 v_q;
void main() {
  vec4 pos = vec4(a_position, 1);
  pos = cc_matViewProj * pos;
  v_uv0 = a_uv0;
  v_uv1 = a_uv1;
  v_p = a_p;
  v_q = a_q;
  gl_Position = pos;
}

glsl3.frag:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec2 v_uv0;
in vec2 v_uv1;
in vec2 v_p;
in vec2 v_q;
uniform sampler2D texture;
void main()
{
  vec2 uv = v_uv0.xy;
  uv = uv * v_p + v_q;
  vec2 offset = v_uv1 * cc_time.x;
  uv = fract(uv - offset);
  uv = (uv - v_q) / v_p;
  vec4 col = texture(texture, uv);
  gl_FragColor = col;
}

glsl1.vert:
