uniform mat4 cc_matViewProj;
attribute vec3 a_position;
attribute vec2 a_uv0;
attribute vec2 a_uv1;
attribute vec2 a_p;
attribute vec2 a_q;
varying vec2 v_uv0;
varying vec2 v_uv1;
varying vec2 v_p;
varying vec2 v_q;
void main() {
  vec4 pos = vec4(a_position, 1);
  pos = cc_matViewProj * pos;
  v_uv0 = a_uv0;
  v_uv1 = a_uv1;
  v_p = a_p;
  v_q = a_q;
  gl_Position = pos;
}

glsl1.frag:
precision highp float;
uniform vec4 cc_time;
varying vec2 v_uv0;
varying vec2 v_uv1;
varying vec2 v_p;
varying vec2 v_q;
uniform sampler2D texture;
void main()
{
  vec2 uv = v_uv0.xy;
  uv = uv * v_p + v_q;
  vec2 offset = v_uv1 * cc_time.x;
  uv = fract(uv - offset);
  uv = (uv - v_q) / v_p;
  vec4 col = texture2D(texture, uv);
  gl_FragColor = col;
}
